interface IDeviceProtocol { string Name { get; } string Read(); }

class ModbusProto : IDeviceProtocol {
    public string Name => "Modbus";
    public string Read() { return "PLC data ok"; }
}

class SerialProto : IDeviceProtocol {
    public string Name => "Serial";
    public string Read() { return "Serial data ok"; }
}

var devices = new List<IDeviceProtocol> { new ModbusProto(), new SerialProto() };
foreach (var d in devices) {
    Print($"{d.Name}连接");
    Print(d.Read());
    Print($"{d.Name}断开");
}
